static void sbi_shutdown(void) {
  register uint64 a0 __asm__("a0") = 0;
  register uint64 a6 __asm__("a6") = 0;
  register uint64 a7 __asm__("a7") = 0x53525354;
  __asm__ volatile("ecall" : "+r"(a0) : "r"(a6), "r"(a7) : "memory");
