}

// run one test ELF/Script in a forked child
static void run_one_test(char *name, char *path) {
  safestrcpy(myproc()->contest_path, path, sizeof(myproc()->contest_path));
  int pid = kfork();
  myproc()->contest_path[0] = 0;
  if (pid < 0) return;
  if (pid == 0) {
      // 子进程：构造 argv 并 exec
      char *argv[] = { name, 0 };
      kexec(path, argv); 

      // 🚨 核心修复：如果 kexec 失败，我们在 kexec 内部已经设置了 p->killed = 1。
      // 这里直接死循环，等待调度器自动回收这个被 killed 的进程！
      // 绝对不要调用 exit(0)，也不要用 <stdlib.h>！
      for(;;); 
  }
  kwait(0);
}

// scan a directory and run each file as a test
static void run_test_dir(char *dirpath, char *group) {
  printf("#### OS COMP TEST GROUP START %s ####\n", group);

  struct inode *dir = namei(dirpath);
  if (!dir) {
      printf("#### OS COMP TEST GROUP END %s ####\n", group); 
      return; 
  }

  ilock(dir);
  if (dir->type != T_DIR) { iunlockput(dir); printf("#### OS COMP TEST GROUP END %s ####\n", group); return; }

  uchar *d_buf = (uchar *)kalloc();
  if (!d_buf) { iunlockput(dir); printf("#### OS COMP TEST GROUP END %s ####\n", group); return; }

  uint off = 0, buf_base = ~0u;

  while (off < dir->size) {
    uint blk = off % BSIZE;
    if (blk == 0 || buf_base != (off & ~(uint)(BSIZE - 1))) {
      buf_base = off & ~(uint)(BSIZE - 1);
      if (readi(dir, 0, (uint64)d_buf, buf_base, BSIZE) == -1) break;
    }
    struct ext4_dir_entry *de = (struct ext4_dir_entry *)(d_buf + (off - buf_base));
    if (de->rec_len == 0) break;

    // 🚨 核心修改 1：不再限制 file_type == EXT4_FT_REG_FILE！
    // 只要 inode 有效，且不是 . 和 ..，统统交给 run_one_test！
    // sys_exec 里的 Shebang 拦截会自动处理 .sh 脚本！
    if (de->inode != 0 && de->name_len > 1) {
      char name[256]; memmove(name, de->name, de->name_len); name[de->name_len] = 0;

      // 跳过 . 和 ..
      if (name[0] == '.') { off += de->rec_len; continue; }

      // 🚨 核心修复：过滤掉动态链接库（.so）文件！它们不能被直接 exec！
      char *dot = name;
      while (*dot && *dot != '.') dot++; // 找到最后一个 '.'
      if (*dot == '.' && *(dot+1) == 's' && *(dot+2) == 'o') {
          // 如果是 .so 或 .so.1 等，直接跳过
          off += de->rec_len;
          continue;
      }

      char full[300];
      safestrcpy(full, dirpath, sizeof(full));
      int dl = strlen(dirpath);
      full[dl] = '/';
      safestrcpy(full + dl + 1, name, sizeof(full) - dl - 1);

      iunlock(dir);
      run_one_test(name, full);
      ilock(dir);
    }
    off += de->rec_len;
  }
  kfree(d_buf);
  iunlock(dir);
  iput(dir);

  printf("#### OS COMP TEST GROUP END %s ####\n", group);
}

